//
// Let k_L be the number of visible people on the left side.
// To achieve k_L, exactly k_L people out of L_count must choose 'L'.
// The remaining L_count - k_L people must choose 'R'.
// Number of ways to choose directions on the left side to see k_L people: C(L_count, k_L).
//
// Let k_R be the number of visible people on the right side.
// To achieve k_R, exactly k_R people out of R_count must choose 'R'.
// The remaining R_count - k_R people must choose 'L'.
// Number of ways to choose directions on the right side to see k_R people: C(R_count, k_R).
//
// We need the total number of visible people k_L + k_R = k.
// So, k_R = k - k_L.
//
// We iterate over all possible values for k_L (0 <= k_L <= L_count and 0 <= k_L <= k).
// For a fixed k_L, we must have k_R = k - k_L.
// We must also satisfy the constraints on k_R: 0 <= k_R <= R_count.
// This means: 0 <= k - k_L <= R_count.
// k - k_L >= 0  => k_L <= k
// k - k_L <= R_count => k - R_count <= k_L
//
// Combining constraints on k_L:
// max(0, k - R_count) <= k_L <= min(L_count, k)
//
// Total ways = 2 * Sum_{k_L} [ C(L_count, k_L) * C(R_count, k - k_L) ]
// where the sum is over valid k_L.
// The factor 2 accounts for the 2 choices of direction for the person at pos.
//
// We need a function to calculate combinations C(n, r) modulo 10^9 + 7.

const MOD = 1000000007

// Modular exponentiation: (base^exp) % mod
func power(base, exp int64) int64 {
	res := int64(1)
	base %= MOD
	for exp > 0 {
		if exp%2 == 1 {
			res = (res * base) % MOD
		}
		base = (base * base) % MOD
		exp /= 2
	}
	return res
}

