	fact = make([]int64, maxN+1)
	invFact = make([]int64, maxN+1)
	fact[0] = 1
	for i := int64(1); i <= maxN; i++ {
		fact[i] = (fact[i-1] * i) % MOD
	}
	invFact[maxN] = modInverse(fact[maxN])
	for i := maxN - 1; i >= 0; i-- {
		invFact[i] = (invFact[i+1] * (i + 1)) % MOD
	}
}

// Combination C(n, r) % MOD
func combinations(n, r int64) int64 {
	if r < 0 || r > n {
		return 0
	}
	if r == 0 || r == n {
		return 1
	}
	if r > n/2 {
		r = n - r
	}
