	// Precompute factorials up to n
	precomputeFactorials(n)

	L_count := pos
	R_count := n - 1 - pos

	totalWays := int64(0)

	// Determine the range for k_L
	// k_L must satisfy:
	// 1. 0 <= k_L <= L_count
	// 2. k_R = k - k_L must satisfy 0 <= k_R <= R_count
	//    k - k_L >= 0  => k_L <= k
	//    k - k_L <= R_count => k_L >= k - R_count

	startKL := int64(0)
	if k - R_count > startKL {
		startKL = k - R_count
	}

	endKL := int64(L_count)
	if k < endKL {
		endKL = k
	}

	// Ensure startKL and endKL are within valid bounds [0, min(L_count, k)]
	if startKL < 0 {
		startKL = 0
	}
	if endKL > L_count {
		endKL = L_count
	}
	if endKL > k {
		endKL = k
	}

	for kL := startKL; kL <= endKL; kL++ {
		kR := k - kL

		// Check final consistency (though derived constraints should handle this)
		if kR < 0 || kR > R_count {
			continue
		}

		// Ways for the left side: C(L_count, kL)
		waysL := combinations(L_count, kL)

		// Ways for the right side: C(R_count, kR)
		waysR := combinations(R_count, kR)

		// Contribution for this (kL, kR) split
		contribution := (waysL * waysR) % MOD

		totalWays = (totalWays + contribution) % MOD
	}

	// The person at 'pos' can choose 'L' or 'R' (2 possibilities), and this doesn't affect k.
	result := (totalWays * 2) % MOD
	return result
