	// There are 'rightCount' people. We need exactly 'r' of them to choose 'R', where 0 <= r <= rightCount.
	// The number of ways to choose 'r' people from 'rightCount' to choose 'R' is C(rightCount, r).
	// The remaining (rightCount - r) people must choose 'L'.

	// Total ways = Sum over all possible splits k = l + r: [Ways to get l from left] * [Ways to get r from right] * [Ways for pos]

	totalWays := int64(0)

	// Iterate over the number of people seen from the left side (l)
	for l := int64(0); l <= leftCount; l++ {
		r := k - l // Required number seen from the right side

		// Check if r is valid for the right side
		if r < 0 || r > rightCount {
			continue
		}

		// Ways to achieve l from left: C(leftCount, l)
		waysLeft := nCk(leftCount, l)

		// Ways to achieve r from right: C(rightCount, r)
		waysRight := nCk(rightCount, r)

		// Contribution from left and right side combinations
		contribution := (waysLeft * waysRight) % MOD

		// --- Factor for person at pos ---
		// The person at pos can choose 'L' or 'R' (2 options), and this choice does not affect the count k.
		// The number of ways for pos is always 2 (unless n=1, which is covered by the general case).
		// If n=1, leftCount=0, rightCount=0. If k=0, l=0, r=0. waysLeft=1, waysRight=1. Contribution=1. We need to multiply by 2.

		// If n > 1, there are 2 ways for pos.
		// If n = 1, pos=0. leftCount=0, rightCount=0. k must be 0. Contribution = 1. We multiply by 2.
		// It seems the factor is always 2 if n >= 1.

		waysPos := int64(2)

		// Edge case: If n=1, pos=0, leftCount=0, rightCount=0. k must be 0.
		// l=0, r=0. waysLeft=1, waysRight=1. contribution=1.
		// If we multiply by 2, the answer is 2, which matches Example 3.

		term := (contribution * waysPos) % MOD
		totalWays = (totalWays + term) % MOD
	}

	return totalWays
}
